## 4.2.6 Service Demand Service (NEW v2.1)

### 4.2.6.1 Purpose

Manage fleet availability requirements by day type. This is a **hard constraint** for the optimizer - it cannot approve maintenance schedules that would violate minimum train availability.

### 4.2.6.2 Implementation

```typescript
interface ServiceDemand {
  id: string;
  fleetId: string;
  effectiveDate: Date;
  dayType: 'WEEKDAY' | 'SATURDAY' | 'SUNDAY' | 'HOLIDAY';

  minTrainsRequired: number;
  peakAmRequirement?: number;
  middayRequirement?: number;
  peakPmRequirement?: number;
  standbyBuffer: number;
}

interface AvailabilityValidation {
  isValid: boolean;
  availableTrains: number;
  requiredTrains: number;
  shortfall: number;
  unavailableTrains: string[];  // Train IDs
  trainsInMaintenance: string[]; // Train IDs
}

class ServiceDemandService {
  constructor(
    private db: Database,
    private unavailabilityService: UnavailabilityService
  ) {}

  /**
   * Get service demand for a specific date
   */
  async getDemand(fleetId: string, targetDate: Date): Promise<ServiceDemand> {
    const dayType = this.getDayType(targetDate);

    const demand = await this.db
      .select()
      .from(serviceDemand)
      .where(and(
        eq(serviceDemand.fleetId, fleetId),
        eq(serviceDemand.dayType, dayType),
        lte(serviceDemand.effectiveDate, targetDate)
      ))
      .orderBy(desc(serviceDemand.effectiveDate))
      .limit(1);

    if (demand.length === 0) {
      // Return default: 85% of fleet
      const fleetSize = await this.getFleetSize(fleetId);
      return {
        id: 'default',
        fleetId,
        effectiveDate: targetDate,
        dayType,
        minTrainsRequired: Math.ceil(fleetSize * 0.85),
        standbyBuffer: 2
      };
    }

    return demand[0];
  }

  /**
   * Validate that enough trains will be available on a date
   */
  async validateAvailability(
    fleetId: string, 
    targetDate: Date,
    additionalUnavailable: string[] = []  // Train IDs to exclude (e.g., proposed PM)
  ): Promise<AvailabilityValidation> {
    const demand = await this.getDemand(fleetId, targetDate);

    // Get all trains in fleet
    const allTrains = await this.db
      .select()
      .from(trains)
      .where(and(
        eq(trains.fleetId, fleetId),
        eq(trains.active, true)
      ));

    // Get unavailable trains
    const unavailable = await this.unavailabilityService.getActiveUnavailability();
    const unavailableIds = new Set(unavailable.map(u => u.trainId));

    // Get trains in maintenance on this date
    const inMaintenance = await this.db
      .select()
      .from(pmSchedule)
      .where(and(
        eq(pmSchedule.targetDate, targetDate),
        inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
        isNull(pmSchedule.scenarioId)
      ));
    const maintenanceIds = new Set(inMaintenance.map(pm => pm.trainId));

    // Add proposed unavailable
    const proposedIds = new Set(additionalUnavailable);

    // Calculate available
    const availableTrains = allTrains.filter(t => 
      !unavailableIds.has(t.id) && 
      !maintenanceIds.has(t.id) &&
      !proposedIds.has(t.id) &&
      t.fitnessStatus === 'FIT'
    );

    const required = demand.minTrainsRequired + demand.standbyBuffer;
    const shortfall = Math.max(0, required - availableTrains.length);

    return {
      isValid: shortfall === 0,
      availableTrains: availableTrains.length,
      requiredTrains: required,
      shortfall,
      unavailableTrains: Array.from(unavailableIds),
      trainsInMaintenance: Array.from(maintenanceIds)
    };
  }

  /**
   * Find dates where service demand would be violated by proposed maintenance
   */
  async findViolations(
    fleetId: string,
    proposedPMs: { trainId: string; date: Date }[],
    horizonDays: number = 90
  ): Promise<{ date: Date; validation: AvailabilityValidation }[]> {
    const violations: { date: Date; validation: AvailabilityValidation }[] = [];

    // Group proposed PMs by date
    const pmsByDate = new Map<string, string[]>();
    for (const pm of proposedPMs) {
      const dateKey = pm.date.toISOString().split('T')[0];
      if (!pmsByDate.has(dateKey)) {
        pmsByDate.set(dateKey, []);
      }
      pmsByDate.get(dateKey)!.push(pm.trainId);
    }

    // Check each date with proposed PMs
    for (const [dateKey, trainIds] of pmsByDate) {
      const validation = await this.validateAvailability(
        fleetId, 
        new Date(dateKey), 
        trainIds
      );

      if (!validation.isValid) {
        violations.push({ date: new Date(dateKey), validation });
      }
    }

    return violations;
  }

  private getDayType(date: Date): ServiceDemand['dayType'] {
    // TODO: Integrate with holiday calendar
    const dayOfWeek = date.getDay();
    if (dayOfWeek === 0) return 'SUNDAY';
    if (dayOfWeek === 6) return 'SATURDAY';
    return 'WEEKDAY';
  }

  private async getFleetSize(fleetId: string): Promise<number> {
    const result = await this.db
      .select({ count: count() })
      .from(trains)
      .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));
    return result[0].count;
  }
}
