/**
 * MMS Man-hour Leveling Worker Processor
 *
 * BullMQ job processor for workload balancing across time periods.
 * Projects workforce requirements and generates adjustment recommendations
 * to prevent overload/underutilization of depot maintenance resources.
 *
 * Leveling Strategies (priority order):
 * 1. ADVANCE_PM (1.1x cost, LOW risk)
 * 2. DEFER_PM (1.05x cost, LOW risk)
 * 3. ADD_OVERTIME (1.5x cost, NO risk)
 * 4. CROSS_DEPOT (1.3x cost, MEDIUM risk)
 * 5. ADD_CONTRACTOR (2.0x cost, MEDIUM risk)
 * 6. MANUAL_REVIEW (flagged for high unresolvable overload)
 *
 * Job Flow:
 * 1. Receive ManhourLevelingJobData from queue
 * 2. Load PM schedule and depot capacity
 * 3. Calculate raw man-hour projections
 * 4. Identify overloaded/underutilized periods
 * 5. Apply leveling strategies in priority order
 * 6. Generate proposed adjustments
 * 7. Store results and broadcast via WebSocket
 *
 * @see specs/004-domain-services.md Section 4.6
 */

import { logger } from '../../lib/logging/logger';
import { withSpan } from '../../lib/tracing';
import { type WorkerJobContext } from '../index';
import { type ManhourLevelingJobData } from '../../lib/queue';
import { getManHourLevelingService, type LevelingResult } from '../../services';

// =============================================================================
// Worker Configuration
// =============================================================================

const log = logger.child({ worker: 'manhour-leveling' });

// =============================================================================
// Job Processor
// =============================================================================

/**
 * Process man-hour leveling job
 *
 * Projects workforce requirements and generates leveling recommendations.
 * Applies multi-strategy workload balancing to achieve optimal utilization.
 */
export async function processManhourLevelingJob(
  context: WorkerJobContext<ManhourLevelingJobData>
): Promise<LevelingResult> {
  return withSpan('worker.manhour_leveling.process', async (span) => {
    const { id, data } = context;
    const { depotId, periodStart, periodEnd, strategies } = data;

    span.setAttribute('jobId', id);
    span.setAttribute('periodStart', periodStart);
    span.setAttribute('periodEnd', periodEnd);
    if (depotId) {
      span.setAttribute('depotId', depotId);
    }
    if (strategies) {
      span.setAttribute('strategies', strategies.join(','));
    }

    log.info(
      {
        jobId: id,
        depotId: depotId ?? 'all',
        periodStart,
        periodEnd,
        strategies: strategies ?? 'default',
      },
      'Processing man-hour leveling job'
    );

    // Calculate horizon weeks from period
    const startDate = new Date(periodStart);
    const endDate = new Date(periodEnd);
    const horizonWeeks = Math.ceil((endDate.getTime() - startDate.getTime()) / (7 * 24 * 60 * 60 * 1000));

    span.setAttribute('horizonWeeks', horizonWeeks);

    // Update progress: initializing
    await context.updateProgress({ stage: 'INITIALIZING', percent: 5 });
    await context.log('Initializing man-hour leveling');

    // Get man-hour leveling service
    const levelingService = getManHourLevelingService();

    // Update progress: loading data
    await context.updateProgress({ stage: 'LOADING_DATA', percent: 15 });
    await context.log(`Loading PM schedule and capacity data for ${horizonWeeks} weeks`);

    // Update progress: projecting workload
    await context.updateProgress({ stage: 'PROJECTING', percent: 30 });
    await context.log('Calculating raw man-hour projections');

    // Update progress: identifying imbalances
    await context.updateProgress({ stage: 'ANALYZING', percent: 45 });
    await context.log('Identifying overloaded and underutilized periods');

    // Update progress: applying strategies
    await context.updateProgress({ stage: 'LEVELING', percent: 60 });
    await context.log('Applying leveling strategies');

    // Run projection and leveling
    // The service handles:
    // - Loading PM schedule within horizon
    // - Calculating raw man-hour requirements
    // - Loading depot capacity configurations
    // - Identifying imbalances (overload >100%, underutilized <70%)
    // - Applying strategies in priority order
    // - Generating proposed adjustments
    const result = await levelingService.generateProjections({
      horizonWeeks,
      depotIds: depotId ? [depotId] : undefined,
      granularity: 'WEEKLY',
    });

    // Update progress: finalizing
    await context.updateProgress({ stage: 'FINALIZING', percent: 90 });

    // Calculate summary metrics
    const { original, leveled, adjustments, improvement } = result;
    const overloadedBefore = original.projections.filter((p) => p.isOverloaded).length;
    const overloadedAfter = leveled.projections.filter((p) => p.isOverloaded).length;
    const underutilizedBefore = original.projections.filter((p) => p.isUnderutilized).length;
    const underutilizedAfter = leveled.projections.filter((p) => p.isUnderutilized).length;

    log.info(
      {
        jobId: id,
        projectionRunId: result.projectionRunId,
        horizonWeeks: result.horizonWeeks,
        depots: result.depotIds.length,
        overloadedBefore,
        overloadedAfter,
        underutilizedBefore,
        underutilizedAfter,
        adjustments: adjustments.length,
        utilizationDelta: improvement.utilizationDelta,
        totalCostImpact: improvement.totalCostImpact,
      },
      'Man-hour leveling complete'
    );

    await context.log(
      `Leveling complete: ${overloadedBefore} → ${overloadedAfter} overloaded periods, ` +
        `${underutilizedBefore} → ${underutilizedAfter} underutilized periods`
    );

    await context.log(
      `Generated ${adjustments.length} adjustments, ` +
        `utilization improved by ${improvement.utilizationDelta.toFixed(1)}%`
    );

    // Log proposed adjustments by type
    const adjustmentsByType: Record<string, number> = {};
    for (const adj of adjustments) {
      adjustmentsByType[adj.type] = (adjustmentsByType[adj.type] ?? 0) + 1;
    }

    if (Object.keys(adjustmentsByType).length > 0) {
      const typeSummary = Object.entries(adjustmentsByType)
        .map(([type, count]) => `${type}: ${count}`)
        .join(', ');
      await context.log(`Adjustment breakdown: ${typeSummary}`);
    }

    // Log high-risk adjustments that need attention
    const highRiskAdjustments = adjustments.filter((a) => a.riskLevel === 'MEDIUM' || a.riskLevel === 'HIGH');
    if (highRiskAdjustments.length > 0) {
      log.warn(
        {
          jobId: id,
          count: highRiskAdjustments.length,
        },
        'High-risk adjustments require review'
      );
      await context.log(`⚠️ ${highRiskAdjustments.length} adjustments require supervisor review`);

      for (const adj of highRiskAdjustments.slice(0, 3)) {
        await context.log(`  - ${adj.type}: ${adj.reason}`);
      }
    }

    // Log manual review items
    const manualReview = adjustments.filter((a) => a.type === 'MANUAL_REVIEW');
    if (manualReview.length > 0) {
      log.warn(
        {
          jobId: id,
          count: manualReview.length,
        },
        'Unresolvable overloads flagged for manual review'
      );
      await context.log(`🔴 ${manualReview.length} periods flagged for MANUAL_REVIEW - capacity insufficient`);
    }

    // Record metrics for Prometheus
    span.setAttribute('leveling.projectionRunId', result.projectionRunId);
    span.setAttribute('leveling.depotCount', result.depotIds.length);
    span.setAttribute('leveling.overloadedBefore', overloadedBefore);
    span.setAttribute('leveling.overloadedAfter', overloadedAfter);
    span.setAttribute('leveling.adjustments', adjustments.length);
    span.setAttribute('leveling.utilizationDelta', improvement.utilizationDelta);
    span.setAttribute('leveling.totalCostImpact', improvement.totalCostImpact);

    // Update progress: complete
    await context.updateProgress({ stage: 'COMPLETE', percent: 100 });

    return result;
  });
}

/**
 * Register the man-hour leveling worker
 */
export function registerManhourLevelingWorker(): void {
  log.info('Man-hour leveling worker processor available for registration');
}

