     1→/**
     2→ * MMS Drift Monitor Worker Processor
     3→ *
     4→ * BullMQ job processor for drift analysis between baselines and current state.
     5→ * Runs nightly to detect mileage drift, PM schedule drift, and generate alerts.
     6→ *
     7→ * Job Flow:
     8→ * 1. Receive DriftMonitorJobData from queue
     9→ * 2. Fetch baseline and current train data
    10→ * 3. Run drift analysis via DriftMonitorService
    11→ * 4. Generate alerts if thresholds exceeded
    12→ * 5. Store results and broadcast via WebSocket
    13→ *
    14→ * @see specs/004-domain-services.md Section 4.8
    15→ */
    16→
    17→import { logger } from '../../lib/logging/logger';
    18→import { withSpan } from '../../lib/tracing';
    19→import { type WorkerJobContext } from '../index';
    20→import { type DriftMonitorJobData } from '../../lib/queue';
    21→import { getDriftMonitorService, type DriftAnalysisResult } from '../../services';
    22→
    23→// =============================================================================
    24→// Worker Configuration
    25→// =============================================================================
    26→
    27→const log = logger.child({ worker: 'drift-monitor' });
    28→
    29→// =============================================================================
    30→// Job Processor
    31→// =============================================================================
    32→
    33→/**
    34→ * Process drift monitor job
    35→ *
    36→ * Runs drift analysis comparing current fleet state against published baseline.
    37→ * Generates alerts when drift thresholds are exceeded.
    38→ */
    39→export async function processDriftMonitorJob(
    40→  context: WorkerJobContext<DriftMonitorJobData>
    41→): Promise<DriftAnalysisResult> {
    42→  return withSpan('worker.drift_monitor.process', async (span) => {
    43→    const { id, data } = context;
    44→    const { baselineId, trainIds } = data;
    45→
    46→    span.setAttribute('jobId', id);
    47→    span.setAttribute('baselineId', baselineId);
    48→    span.setAttribute('hasTrainFilter', !!trainIds);
    49→    if (trainIds) {
    50→      span.setAttribute('trainCount', trainIds.length);
    51→    }
    52→
    53→    log.info(
    54→      { jobId: id, baselineId, trainIds: trainIds?.length ?? 'all' },
    55→      'Processing drift monitor job'
    56→    );
    57→
    58→    // Update progress: initializing
    59→    await context.updateProgress({ stage: 'INITIALIZING', percent: 10 });
    60→    await context.log('Initializing drift analysis');
    61→
    62→    // Get drift monitor service
    63→    const driftService = getDriftMonitorService();
    64→
    65→    // Update progress: analyzing
    66→    await context.updateProgress({ stage: 'ANALYZING', percent: 30 });
    67→    await context.log(`Running drift analysis for baseline ${baselineId}`);
    68→
    69→    // Run drift analysis
    70→    // The service's runDriftAnalysis handles:
    71→    // - Fetching baseline data
    72→    // - Comparing against current fleet state
    73→    // - Calculating mileage and PM drift
    74→    // - Generating alerts based on thresholds
    75→    const result = await driftService.runDriftAnalysis();
    76→
    77→    // Update progress: finalizing
    78→    await context.updateProgress({ stage: 'FINALIZING', percent: 90 });
    79→
    80→    if (result.skipped) {
    81→      log.info({ jobId: id, reason: result.reason }, 'Drift analysis skipped');
    82→      await context.log(`Analysis skipped: ${result.reason}`);
    83→    } else {
    84→      const { summary, trainAnalyses, alerts } = result;
    85→
    86→      log.info(
    87→        {
    88→          jobId: id,
    89→          totalTrains: summary.totalTrains,
    90→          trainsWithDrift: summary.trainsWithDrift,
    91→          trainsRequiringReplan: summary.trainsRequiringReplan,
    92→          alertCount: alerts.length,
    93→        },
    94→        'Drift analysis complete'
    95→      );
    96→
    97→      await context.log(
    98→        `Analyzed ${summary.totalTrains} trains, ${summary.trainsWithDrift} with drift, ` +
    99→          `${summary.trainsRequiringReplan} requiring replan, ${alerts.length} alerts generated`
   100→      );
   101→
   102→      // Log high-severity alerts
   103→      const criticalAlerts = alerts.filter((a) => a.severity === 'CRITICAL');
   104→      if (criticalAlerts.length > 0) {
   105→        log.warn(
   106→          { jobId: id, criticalAlerts: criticalAlerts.length },
   107→          'Critical drift alerts detected'
   108→        );
   109→
   110→        for (const alert of criticalAlerts) {
   111→          await context.log(`CRITICAL: ${alert.message}`);
   112→        }
   113→      }
   114→
   115→      // Record metrics for Prometheus
   116→      span.setAttribute('drift.totalTrains', summary.totalTrains);
   117→      span.setAttribute('drift.trainsWithDrift', summary.trainsWithDrift);
   118→      span.setAttribute('drift.trainsRequiringReplan', summary.trainsRequiringReplan);
   119→      span.setAttribute('drift.avgFleetDriftPct', summary.avgFleetDriftPct);
   120→      span.setAttribute('drift.alertCount', alerts.length);
   121→
   122→      // Filter by trainIds if specified
   123→      if (trainIds && trainIds.length > 0) {
   124→        const filteredAnalyses = trainAnalyses.filter((a) =>
   125→          trainIds.includes(a.trainId)
   126→        );
   127→        log.debug(
   128→          {
   129→            jobId: id,
   130→            original: trainAnalyses.length,
   131→            filtered: filteredAnalyses.length,
   132→          },
   133→          'Filtered train analyses by trainIds'
   134→        );
   135→      }
   136→    }
   137→
   138→    // Update progress: complete
   139→    await context.updateProgress({ stage: 'COMPLETE', percent: 100 });
   140→
   141→    return result;
   142→  });
   143→}
   144→
   145→/**
   146→ * Register the drift monitor worker
   147→ */
   148→export function registerDriftMonitorWorker(): void {
