     1→/**
     2→ * MMS Maximo Sync Worker Processor
     3→ *
     4→ * BullMQ job processor for bidirectional synchronization with IBM Maximo.
     5→ * Handles scheduled push/pull operations, conflict resolution, and polling fallback.
     6→ *
     7→ * Job Flow:
     8→ * 1. Receive MaximoSyncJobData from queue
     9→ * 2. Based on operation type:
    10→ *    - push: Send pending MMS changes to Maximo
    11→ *    - pull: Fetch remote changes from Maximo
    12→ *    - full: Execute both push and pull
    13→ *    - polling: Execute scheduled fallback pull with deduplication
    14→ * 3. Handle conflicts according to resolution strategy
    15→ * 4. Store sync history and update shadow records
    16→ *
    17→ * @see specs/007-integration.md Section 7.4
    18→ */
    19→
    20→import { logger } from '../../lib/logging/logger';
    21→import { withSpan } from '../../lib/tracing';
    22→import { type WorkerJobContext } from '../index';
    23→import { type MaximoSyncJobData } from '../../lib/queue';
    24→import {
    25→  recordMaximoSync,
    26→} from '../../lib/metrics';
    27→import {
    28→  getMaximoSyncService,
    29→  getMaximoPollingService,
    30→  type PushResult,
    31→  type PullResult,
    32→  type ConflictResolution,
    33→} from '../../services';
    34→
    35→// =============================================================================
    36→// Worker Configuration
    37→// =============================================================================
    38→
    39→const log = logger.child({ worker: 'maximo-sync' });
    40→
    41→// =============================================================================
    42→// Result Types
    43→// =============================================================================
    44→
    45→interface MaximoSyncResult {
    46→  operation: 'push' | 'pull' | 'full' | 'polling';
    47→  push?: {
    48→    pushed: number;
    49→    errors: number;
    50→    details?: PushResult[];
    51→  };
    52→  pull?: {
    53→    processed: number;
    54→    updated: number;
    55→    conflicts: number;
    56→    details?: PullResult;
    57→  };
    58→  polling?: {
    59→    processed: number;
    60→    updated: number;
    61→    conflicts: number;
    62→    errors: number;
    63→    duplicatesPrevented: number;
    64→    syncMode: string;
    65→  };
    66→  durationMs: number;
    67→  success: boolean;
    68→}
    69→
    70→// =============================================================================
    71→// Job Processor
    72→// =============================================================================
    73→
    74→/**
    75→ * Process Maximo sync job
    76→ *
    77→ * Executes bidirectional synchronization between MMS and Maximo.
    78→ * Supports push (MMS→Maximo), pull (Maximo→MMS), or full (both) operations.
    79→ */
    80→export async function processMaximoSyncJob(
    81→  context: WorkerJobContext<MaximoSyncJobData>
    82→): Promise<MaximoSyncResult> {
    83→  return withSpan('worker.maximo_sync.process', async (span) => {
    84→    const { id, data } = context;
    85→    const { operation, pmScheduleIds, depotId, force, conflictResolution } = data;
    86→    const startTime = Date.now();
    87→
    88→    span.setAttribute('jobId', id);
    89→    span.setAttribute('operation', operation);
    90→    span.setAttribute('hasSpecificPms', !!pmScheduleIds);
    91→    span.setAttribute('depotId', depotId ?? 'all');
    92→    span.setAttribute('force', force ?? false);
    93→
    94→    log.info(
    95→      { jobId: id, operation, pmScheduleIds: pmScheduleIds?.length, depotId, force },
    96→      'Processing Maximo sync job'
    97→    );
    98→
    99→    const result: MaximoSyncResult = {
   100→      operation,
   101→      durationMs: 0,
   102→      success: true,
   103→    };
   104→
   105→    const maximoService = getMaximoSyncService();
   106→
   107→    try {
   108→      // Execute push operation
   109→      if (operation === 'push' || operation === 'full') {
   110→        await context.updateProgress({ stage: 'PUSHING', percent: 10 });
   111→        await context.log('Starting push sync (MMS → Maximo)');
   112→
   113→        const pushResult = await executePush(
   114→          maximoService,
   115→          pmScheduleIds,
   116→          context
   117→        );
   118→
   119→        result.push = pushResult;
   120→
   121→        log.info(
   122→          { jobId: id, pushed: pushResult.pushed, errors: pushResult.errors },
   123→          'Push sync complete'
   124→        );
   125→      }
   126→
   127→      // Execute pull operation
   128→      if (operation === 'pull' || operation === 'full') {
   129→        const progressBase = operation === 'full' ? 50 : 10;
   130→        await context.updateProgress({ stage: 'PULLING', percent: progressBase });
   131→        await context.log('Starting pull sync (Maximo → MMS)');
   132→
   133→        const pullResult = await executePull(
   134→          maximoService,
   135→          conflictResolution as ConflictResolution | undefined,
   136→          context
   137→        );
   138→
   139→        result.pull = pullResult;
   140→
   141→        log.info(
   142→          {
   143→            jobId: id,
   144→            processed: pullResult.processed,
   145→            updated: pullResult.updated,
