   123→        jobId: id,
   124→        type,
   125→        format,
   126→        requestedBy,
   127→        filters: Object.keys(filters ?? {}),
   128→      },
   129→      'Processing report generation job'
   130→    );
   131→
   132→    // Update progress: initializing
   133→    await context.updateProgress({ stage: 'INITIALIZING', percent: 5 });
   134→    await context.log(`Initializing ${type} report generation (${format})`);
   135→
   136→    // Ensure output directory exists
   137→    await ensureOutputDir();
   138→
   139→    // Update progress: fetching data
   140→    await context.updateProgress({ stage: 'FETCHING_DATA', percent: 20 });
   141→    await context.log('Fetching report data');
   142→
   143→    // Fetch data based on report type
   144→    const reportData = await fetchReportData(type, filters);
   145→    span.setAttribute('report.dataRows', reportData.rowCount);
   146→
   147→    await context.log(`Loaded ${reportData.rowCount} records for report`);
   148→
   149→    // Update progress: generating report
   150→    await context.updateProgress({ stage: 'GENERATING', percent: 50 });
   151→    await context.log(`Generating ${format.toUpperCase()} report`);
   152→
   153→    // Generate report based on format
   154→    let result: ReportResult;
   155→
   156→    if (format === 'excel') {
   157→      result = await generateExcelReport(id, type, reportData);
   158→    } else {
   159→      result = await generatePdfReport(id, type, reportData);
   160→    }
   161→
   162→    // Update progress: finalizing
   163→    await context.updateProgress({ stage: 'FINALIZING', percent: 90 });
   164→
   165→    log.info(
   166→      {
   167→        jobId: id,
   168→        filePath: result.filePath,
   169→        fileSizeBytes: result.fileSizeBytes,
   170→        downloadUrl: result.downloadUrl,
   171→        expiresAt: result.expiresAt,
   172→      },
   173→      'Report generation complete'
   174→    );
   175→
   176→    await context.log(
   177→      `Report generated: ${result.fileName} (${formatFileSize(result.fileSizeBytes)})`
   178→    );
   179→    await context.log(`Download URL: ${result.downloadUrl}`);
   180→    await context.log(`Expires: ${result.expiresAt.toISOString()}`);
   181→
   182→    // Record metrics
   183→    span.setAttribute('report.fileSizeBytes', result.fileSizeBytes);
   184→    span.setAttribute('report.fileName', result.fileName);
   185→
   186→    // Update progress: complete
   187→    await context.updateProgress({ stage: 'COMPLETE', percent: 100 });
   188→
   189→    return result;
   190→  });
   191→}
