   289→/**
   290→ * Fetch PM schedule data from database
   291→ */
   292→async function fetchPmScheduleData(filters?: Record<string, unknown>): Promise<ReportData> {
   293→  // Parse filters
   294→  const startDate = filters?.['startDate'] as string | undefined;
   295→  const endDate = filters?.['endDate'] as string | undefined;
   296→  const fleetId = filters?.['fleetId'] as string | undefined;
   297→  const depotId = filters?.['depotId'] as string | undefined;
   298→  const statusFilter = filters?.['status'] as string[] | undefined;
   299→
   300→  // Build query conditions
   301→  const conditions = [isNull(pmSchedule.scenarioId)];
   302→
   303→  if (startDate) {
   304→    conditions.push(gte(pmSchedule.targetDate, startDate));
   305→  }
   306→  if (endDate) {
   307→    conditions.push(lte(pmSchedule.targetDate, endDate));
   308→  }
   309→  if (statusFilter?.length) {
   310→    conditions.push(inArray(pmSchedule.status, statusFilter as ('SCHEDULED' | 'IN_PROGRESS' | 'COMPLETED' | 'DEFERRED' | 'CANCELLED')[]));
   311→  }
   312→  if (fleetId) {
   313→    conditions.push(eq(fleets.id, fleetId));
   314→  }
   315→  if (depotId) {
   316→    conditions.push(eq(pmSchedule.assignedDepotId, depotId));
   317→  }
   318→
   319→  // Query with joins
   320→  const results = await db
   321→    .select({
   322→      trainNumber: trains.trainNumber,
   323→      fleetCode: fleets.code,
   324→      pmCode: pmTypes.pmCode,
   325→      targetDate: pmSchedule.targetDate,
   326→      status: pmSchedule.status,
   327→      constraintStart: pmSchedule.constraintStart,
   328→      constraintEnd: pmSchedule.constraintEnd,
   329→      assignedDepot: depots.name,
   330→      assignedTrack: tracks.trackNumber,
   331→      estimatedHours: pmTypes.estimatedHours,
   332→      maximoWoId: pmSchedule.maximoWoId,
   333→      isLocked: pmSchedule.isLocked,
   334→    })
   335→    .from(pmSchedule)
   336→    .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
   337→    .innerJoin(fleets, eq(trains.fleetId, fleets.id))
   338→    .innerJoin(pmTypes, eq(pmSchedule.pmTypeId, pmTypes.id))
   339→    .leftJoin(depots, eq(pmSchedule.assignedDepotId, depots.id))
   340→    .leftJoin(tracks, eq(pmSchedule.assignedTrackId, tracks.id))
   341→    .where(and(...conditions))
   342→    .orderBy(asc(pmSchedule.targetDate), asc(trains.trainNumber));
   343→
   344→  const rows: PmScheduleRow[] = results.map((r) => ({
   345→    trainNumber: r.trainNumber,
   346→    fleetCode: r.fleetCode,
   347→    pmCode: r.pmCode,
   348→    targetDate: r.targetDate,
   349→    status: r.status ?? 'SCHEDULED', // Default to SCHEDULED if null
   350→    constraintStart: r.constraintStart,
   351→    constraintEnd: r.constraintEnd,
   352→    assignedDepot: r.assignedDepot,
   353→    assignedTrack: r.assignedTrack,
   354→    estimatedHours: r.estimatedHours ? Number(r.estimatedHours) : null,
   355→    maximoWoId: r.maximoWoId,
   356→    isLocked: r.isLocked ?? false, // Default to false if null
   357→  }));
   358→
   359→  return {
   360→    rowCount: rows.length,
   361→    data: rows as unknown as Record<string, unknown>[],
   362→    metadata: {
   363→      reportType: 'pm_schedule',
   364→      columns: [
   365→        'trainNumber', 'fleetCode', 'pmCode', 'targetDate', 'status',
   366→        'constraintStart', 'constraintEnd', 'assignedDepot', 'assignedTrack',
   367→        'estimatedHours', 'maximoWoId', 'isLocked',
   368→      ],
   369→      generatedAt: new Date().toISOString(),
   370→      filters: { startDate, endDate, fleetId, depotId, status: statusFilter },
   371→    },
   372→  };
   373→}
