   418→/**
   419→ * Fetch drift report data using DriftMonitorService
   420→ */
   421→async function fetchDriftReportData(filters?: Record<string, unknown>): Promise<ReportData> {
   422→  const driftService = getDriftMonitorService();
   423→
   424→  // Run or get latest drift analysis
   425→  const analysisDate = filters?.['analysisDate'] as string | undefined;
   426→  const analysisDateObj = analysisDate ? new Date(analysisDate) : undefined;
   427→  const result: DriftAnalysisResult = await driftService.runDriftAnalysis(analysisDateObj);
   428→
   429→  // Check if analysis was skipped (discriminated union check)
   430→  if (result.skipped) {
   431→    return {
   432→      rowCount: 0,
   433→      data: [],
   434→      metadata: {
   435→        reportType: 'drift_report',
   436→        status: 'SKIPPED',
   437→        reason: result.reason,
   438→        generatedAt: new Date().toISOString(),
   439→        filters,
   440→      },
   441→    };
   442→  }
   443→
   444→  // Type narrowing - result is now DriftAnalysisSuccess
   445→  const successResult = result as DriftAnalysisSuccess;
   446→
   447→  // Extract train analyses
   448→  const trainAnalyses = successResult.trainAnalyses;
   449→
   450→  const rows: DriftReportRow[] = trainAnalyses.map((t: TrainDriftAnalysis) => ({
   451→    trainNumber: t.trainNumber,
   452→    fleetCode: '', // TrainDriftAnalysis doesn't have fleetCode; would need separate lookup
   453→    baselineProjectedKm: t.baselineProjectedKm,
   454→    actualKm: t.actualKm,
   455→    mileageDriftPct: t.mileageDriftPct,
   456→    avgPmDriftDays: t.avgPmDriftDays,
   457→    maxPmDriftDays: t.maxPmDriftDays,
   458→    requiresReplan: t.requiresReplan,
   459→    replanReason: t.replanReason ?? null,
   460→  }));
   461→
   462→  // Get summary and alerts
   463→  const summary = successResult.summary;
   464→  const alerts = successResult.alerts;
   465→
   466→  return {
   467→    rowCount: rows.length,
   468→    data: rows as unknown as Record<string, unknown>[],
   469→    metadata: {
   470→      reportType: 'drift_report',
   471→      baselineId: successResult.baselineId,
   472→      analysisDate: successResult.analysisDate,
   473→      summary: {
   474→        totalTrainsAnalyzed: summary.totalTrains,
   475→        trainsRequiringReplan: summary.trainsRequiringReplan,
   476→        avgMileageDriftPct: summary.avgFleetDriftPct,
   477→        maxPmDriftDays: 0, // Not directly available in summary, would need to calculate
   478→      },
   479→      alerts: alerts.map((a: DriftAlert) => ({
   480→        severity: a.severity,
   481→        type: a.type,
   482→        message: a.message,
   483→        trainNumber: a.trainNumber,
   484→      })),
   485→      columns: [
   486→        'trainNumber', 'fleetCode', 'baselineProjectedKm', 'actualKm', 'mileageDriftPct',
   487→        'avgPmDriftDays', 'maxPmDriftDays', 'requiresReplan', 'replanReason',
   488→      ],
   489→      generatedAt: new Date().toISOString(),
   490→      filters,
   491→    },
   492→  };
   493→}
