   495→/**
   496→ * Fetch TCO projection data using CostingService
   497→ */
   498→async function fetchTcoProjectionData(filters?: Record<string, unknown>): Promise<ReportData> {
   499→  const costingService = getCostingService();
   500→
   501→  // Parse filters - ProjectTCORequest only has horizonYears, scenarioId, depotId
   502→  const horizonYears = (filters?.['horizonYears'] as number) ?? 12;
   503→  const depotId = filters?.['depotId'] as string | undefined;
   504→  const scenarioId = filters?.['scenarioId'] as string | undefined;
   505→
   506→  // Project TCO
   507→  const projection: TCOProjection = await costingService.projectTCO({
   508→    horizonYears,
   509→    depotId,
   510→    scenarioId,
   511→  });
   512→
   513→  // Calculate overhead as 18% of (labor + material) for each year
   514→  const OVERHEAD_RATE = 0.18;
   515→  const rows: TcoProjectionRow[] = projection.projections.map((p: YearlyCost) => {
   516→    const overheadCost = (p.laborCost + p.materialCost) * OVERHEAD_RATE;
   517→    return {
   518→      fiscalYear: p.fiscalYear,
   519→      laborCost: p.laborCost,
   520→      materialCost: p.materialCost,
   521→      overheadCost: Math.round(overheadCost),
   522→      totalCost: p.totalCost,
   523→      pmCount: p.pmCount,
   524→      inflationFactor: p.inflationFactor,
   525→    };
   526→  });
   527→
   528→  // Calculate total overhead cost from the rows
   529→  const totalOverheadCost = rows.reduce((sum, r) => sum + r.overheadCost, 0);
   530→
   531→  return {
   532→    rowCount: rows.length,
   533→    data: rows as unknown as Record<string, unknown>[],
   534→    metadata: {
   535→      reportType: 'tco_projection',
   536→      horizonYears,
   537→      summary: {
   538→        totalLaborCost: projection.summary.totalLaborCost,
   539→        totalMaterialCost: projection.summary.totalMaterialCost,
   540→        totalOverheadCost: totalOverheadCost,
   541→        grandTotal: projection.summary.totalCost,
   542→        npv: projection.summary.npv,
   543→        avgAnnualCost: projection.summary.avgAnnualCost,
   544→      },
   545→      columns: [
   546→        'fiscalYear', 'laborCost', 'materialCost', 'overheadCost', 'totalCost',
   547→        'pmCount', 'inflationFactor',
   548→      ],
   549→      generatedAt: new Date().toISOString(),
   550→      filters: { horizonYears, depotId, scenarioId },
   551→    },
   552→  };
   553→}
