   559→/**
   560→ * Generate Excel report using ExcelJS
   561→ */
   562→async function generateExcelReport(
   563→  jobId: string,
   564→  type: string,
   565→  reportData: ReportData
   566→): Promise<ReportResult> {
   567→  return withSpan('report.generateExcel', async (span) => {
   568→    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
   569→    const fileName = `${type}_${timestamp}.xlsx`;
   570→    const filePath = path.join(REPORTS_OUTPUT_DIR, fileName);
   571→
   572→    span.setAttribute('report.fileName', fileName);
   573→    span.setAttribute('report.filePath', filePath);
   574→
   575→    // Create workbook and worksheet
   576→    const workbook = new ExcelJS.Workbook();
   577→    workbook.creator = 'MMS Report Generator';
   578→    workbook.created = new Date();
   579→
   580→    const worksheet = workbook.addWorksheet(formatReportTitle(type));
   581→
   582→    // Get columns from metadata
   583→    const columns = (reportData.metadata['columns'] as string[]) ?? [];
   584→
   585→    // Configure columns with headers and widths
   586→    worksheet.columns = columns.map((col) => ({
   587→      header: formatColumnHeader(col),
   588→      key: col,
   589→      width: getColumnWidth(col),
   590→    }));
   591→
   592→    // Style header row
   593→    const headerRow = worksheet.getRow(1);
   594→    headerRow.font = { bold: true, color: { argb: 'FFFFFFFF' } };
   595→    headerRow.fill = {
   596→      type: 'pattern',
   597→      pattern: 'solid',
   598→      fgColor: { argb: 'FF2E5A88' }, // MMS blue
   599→    };
   600→    headerRow.alignment = { vertical: 'middle', horizontal: 'center' };
   601→
   602→    // Add data rows
   603→    reportData.data.forEach((row) => {
   604→      const rowData: Record<string, unknown> = {};
   605→      columns.forEach((col) => {
   606→        rowData[col] = formatCellValue(row[col], col);
   607→      });
   608→      worksheet.addRow(rowData);
   609→    });
   610→
   611→    // Apply alternating row colors
   612→    worksheet.eachRow((row, rowNumber) => {
   613→      if (rowNumber > 1 && rowNumber % 2 === 0) {
   614→        row.fill = {
   615→          type: 'pattern',
   616→          pattern: 'solid',
   617→          fgColor: { argb: 'FFF5F5F5' },
   618→        };
   619→      }
   620→    });
   621→
   622→    // Add filters to first row if supported
   623→    if (reportData.rowCount > 0) {
   624→      worksheet.autoFilter = {
   625→        from: { row: 1, column: 1 },
   626→        to: { row: 1, column: columns.length },
   627→      };
   628→    }
   629→
   630→    // Add metadata sheet
   631→    const metaSheet = workbook.addWorksheet('Report Info');
   632→    metaSheet.addRow(['Report Type', formatReportTitle(type)]);
   633→    metaSheet.addRow(['Generated At', reportData.metadata['generatedAt']]);
   634→    metaSheet.addRow(['Total Records', reportData.rowCount]);
   635→
   636→    // Add summary data for specific report types
   637→    if (type === 'tco_projection' && reportData.metadata['summary']) {
   638→      const summary = reportData.metadata['summary'] as Record<string, number>;
   639→      metaSheet.addRow([]);
   640→      metaSheet.addRow(['TCO Summary']);
   641→      metaSheet.addRow(['Total Labor Cost', formatCurrency(summary['totalLaborCost'])]);
   642→      metaSheet.addRow(['Total Material Cost', formatCurrency(summary['totalMaterialCost'])]);
   643→      metaSheet.addRow(['Total Overhead Cost', formatCurrency(summary['totalOverheadCost'])]);
   644→      metaSheet.addRow(['Grand Total', formatCurrency(summary['grandTotal'])]);
   645→      metaSheet.addRow(['NPV', formatCurrency(summary['npv'])]);
   646→      metaSheet.addRow(['Average Annual Cost', formatCurrency(summary['avgAnnualCost'])]);
   647→    }
   648→
   649→    if (type === 'drift_report' && reportData.metadata['summary']) {
   650→      const summary = reportData.metadata['summary'] as Record<string, number>;
   651→      metaSheet.addRow([]);
   652→      metaSheet.addRow(['Drift Analysis Summary']);
   653→      metaSheet.addRow(['Total Trains Analyzed', summary['totalTrainsAnalyzed']]);
   654→      metaSheet.addRow(['Trains Requiring Replan', summary['trainsRequiringReplan']]);
   655→      metaSheet.addRow(['Average Mileage Drift %', `${summary['avgMileageDriftPct']?.toFixed(2)}%`]);
   656→      metaSheet.addRow(['Maximum PM Drift Days', summary['maxPmDriftDays']]);
   657→    }
   658→
   659→    metaSheet.columns = [
   660→      { width: 25 },
   661→      { width: 30 },
   662→    ];
   663→
   664→    // Write to file
   665→    await workbook.xlsx.writeFile(filePath);
   666→
   667→    const stats = await fs.stat(filePath);
   668→    const expiresAt = new Date(Date.now() + REPORT_RETENTION_HOURS * 60 * 60 * 1000);
   669→
   670→    return {
   671→      jobId,
   672→      type,
   673→      format: 'excel',
   674→      filePath,
   675→      fileName,
   676→      fileSizeBytes: stats.size,
   677→      downloadUrl: `${REPORTS_BASE_URL}/${fileName}`,
   678→      expiresAt,
   679→      generatedAt: new Date(),
   680→      rowCount: reportData.rowCount,
   681→    };
   682→  });
   683→}
