   713→    mileageDriftPct: 14,
   714→    avgPmDriftDays: 14,
   715→    maxPmDriftDays: 14,
   716→    requiresReplan: 14,
   717→    replanReason: 25,
   718→    fiscalYear: 12,
   719→    laborCost: 14,
   720→    materialCost: 14,
   721→    overheadCost: 14,
   722→    totalCost: 14,
   723→    pmCount: 10,
   724→    inflationFactor: 14,
   725→  };
   726→  return widths[col] ?? 15;
   727→}
   728→
   729→/**
   730→ * Format column header from camelCase to Title Case
   731→ */
   732→function formatColumnHeader(col: string): string {
   733→  return col
   734→    .replace(/([A-Z])/g, ' $1')
   735→    .replace(/^./, (str) => str.toUpperCase())
   736→    .replace(/Km/g, '(km)')
   737→    .replace(/Pct/g, '(%)')
   738→    .trim();
   739→}
   740→
   741→/**
   742→ * Format cell value for display
   743→ */
   744→function formatCellValue(value: unknown, col: string): string | number | boolean | Date | null {
   745→  if (value === null || value === undefined) return '';
   746→
   747→  // Currency columns
   748→  if (['laborCost', 'materialCost', 'overheadCost', 'totalCost'].includes(col)) {
   749→    return typeof value === 'number' ? value : parseFloat(String(value)) || 0;
   750→  }
   751→
   752→  // Percentage columns
   753→  if (col.includes('Pct')) {
   754→    return typeof value === 'number' ? `${value.toFixed(2)}%` : String(value);
   755→  }
   756→
   757→  // Boolean columns
   758→  if (typeof value === 'boolean') {
   759→    return value ? 'Yes' : 'No';
   760→  }
   761→
   762→  // Date columns
   763→  if (col.includes('Date') && typeof value === 'string') {
   764→    return value;
   765→  }
   766→
   767→  return value as string | number | boolean | Date;
   768→}
   769→
   770→/**
   771→ * Format currency value
   772→ */
   773→function formatCurrency(value: number | undefined): string {
   774→  if (value === undefined) return 'N/A';
   775→  return new Intl.NumberFormat('en-SG', {
   776→    style: 'currency',
   777→    currency: 'SGD',
   778→    minimumFractionDigits: 0,
   779→    maximumFractionDigits: 0,
   780→  }).format(value);
   781→}
   782→
   783→// =============================================================================
   784→// PDF Generation
   785→// =============================================================================
   786→
   787→// Define fonts for pdfmake (using Roboto which comes bundled)
   788→const fonts = {
   789→  Roboto: {
   790→    normal: 'node_modules/pdfmake/build/vfs_fonts.js',
   791→    bold: 'node_modules/pdfmake/build/vfs_fonts.js',
   792→    italics: 'node_modules/pdfmake/build/vfs_fonts.js',
   793→    bolditalics: 'node_modules/pdfmake/build/vfs_fonts.js',
   794→  },
   795→};
   796→
   797→/**
   798→ * Generate PDF report using pdfmake
   799→ */
   800→async function generatePdfReport(
   801→  jobId: string,
   802→  type: string,
   803→  reportData: ReportData
   804→): Promise<ReportResult> {
   805→  return withSpan('report.generatePdf', async (span) => {
   806→    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
   807→    const fileName = `${type}_${timestamp}.pdf`;
   808→    const filePath = path.join(REPORTS_OUTPUT_DIR, fileName);
   809→
   810→    span.setAttribute('report.fileName', fileName);
   811→    span.setAttribute('report.filePath', filePath);
   812→
   813→    // Create PDF document definition
   814→    const docDefinition = createPdfDocDefinition(type, reportData);
   815→
   816→    // Create PDF printer
   817→    const printer = new PdfPrinter(fonts);
   818→    const pdfDoc = printer.createPdfKitDocument(docDefinition);
   819→
   820→    // Write to file using synchronous fs createWriteStream
   821→    await new Promise<void>((resolve, reject) => {
   822→      const writeStream = fsSync.createWriteStream(filePath);
   823→      pdfDoc.pipe(writeStream);
   824→      pdfDoc.end();
   825→      writeStream.on('finish', resolve);
   826→      writeStream.on('error', reject);
   827→    });
   828→
   829→    const stats = await fs.stat(filePath);
   830→    const expiresAt = new Date(Date.now() + REPORT_RETENTION_HOURS * 60 * 60 * 1000);
   831→
   832→    // Estimate page count (roughly 40 rows per page in landscape)
   833→    const estimatedPageCount = Math.max(1, Math.ceil(reportData.rowCount / 40));
   834→
   835→    return {
   836→      jobId,
   837→      type,
   838→      format: 'pdf',
   839→      filePath,
   840→      fileName,
   841→      fileSizeBytes: stats.size,
   842→      downloadUrl: `${REPORTS_BASE_URL}/${fileName}`,
   843→      expiresAt,
   844→      generatedAt: new Date(),
   845→      rowCount: reportData.rowCount,
   846→      pageCount: estimatedPageCount,
   847→    };
   848→  });
   849→}
   850→
   851→/**
   852→ * Create PDF document definition for pdfmake
   853→ */
   854→function createPdfDocDefinition(type: string, reportData: ReportData): TDocumentDefinitions {
   855→  const columns = (reportData.metadata['columns'] as string[]) ?? [];
   856→  const generatedAt = reportData.metadata['generatedAt'] as string;
   857→
   858→  // Build content array
   859→  const content: Content[] = [];
   860→
   861→  // Header
   862→  content.push({
   863→    text: `MMS ${formatReportTitle(type)}`,
   864→    style: 'header',
   865→    margin: [0, 0, 0, 10],
   866→  });
   867→
   868→  // Report info
   869→  content.push({
   870→    text: [
   871→      { text: 'Generated: ', bold: true },
   872→      format(new Date(generatedAt), 'PPpp'),
   873→      '  |  ',
   874→      { text: 'Records: ', bold: true },
   875→      String(reportData.rowCount),
   876→    ],
   877→    style: 'subheader',
   878→    margin: [0, 0, 0, 15],
   879→  });
   880→
   881→  // Add summary section for specific report types
   882→  if (type === 'tco_projection' && reportData.metadata['summary']) {
   883→    content.push(createTcoSummaryContent(reportData.metadata['summary'] as Record<string, number>));
   884→  }
   885→
   886→  if (type === 'drift_report' && reportData.metadata['summary']) {
   887→    content.push(createDriftSummaryContent(
   888→      reportData.metadata['summary'] as Record<string, number>,
   889→      reportData.metadata['alerts'] as Array<{ severity: string; message: string }> | undefined
   890→    ));
   891→  }
   892→
   893→  if (type === 'fleet_status') {
   894→    content.push(createFleetSummaryContent(reportData.data as unknown as FleetStatusRow[]));
   895→  }
   896→
   897→  // Data table
   898→  if (reportData.rowCount > 0 && columns.length > 0) {
   899→    content.push({
   900→      text: 'Detailed Data',
   901→      style: 'sectionHeader',
   902→      margin: [0, 20, 0, 10],
   903→    });
   904→
   905→    content.push(createDataTable(columns, reportData.data));
   906→  } else {
   907→    content.push({
   908→      text: 'No data available for the specified filters.',
   909→      style: 'noData',
   910→      margin: [0, 20, 0, 0],
   911→    });
   912→  }
   913→
   914→  // Footer with page numbers
   915→  return {
   916→    pageSize: 'A4',
   917→    pageOrientation: 'landscape',
   918→    pageMargins: [40, 60, 40, 60],
   919→    header: (currentPage: number, pageCount: number) => ({
   920→      columns: [
   921→        { text: 'MMS Report', style: 'pageHeader' },
