   923→      ],
   924→      margin: [40, 20, 40, 10],
   925→    }),
   926→    footer: () => ({
   927→      text: 'Metro Fleet Mileage Management System - Confidential',
   928→      style: 'footer',
   929→      alignment: 'center',
   930→      margin: [40, 10, 40, 20],
   931→    }),
   932→    content,
   933→    styles: {
   934→      header: {
   935→        fontSize: 18,
   936→        bold: true,
   937→        color: '#2E5A88',
   938→      },
   939→      subheader: {
   940→        fontSize: 10,
   941→        color: '#666666',
   942→      },
   943→      sectionHeader: {
   944→        fontSize: 14,
   945→        bold: true,
   946→        color: '#2E5A88',
   947→      },
   948→      tableHeader: {
   949→        bold: true,
   950→        fontSize: 8,
   951→        color: 'white',
   952→        fillColor: '#2E5A88',
   953→      },
   954→      tableCell: {
   955→        fontSize: 7,
   956→      },
   957→      tableCellAlt: {
