  1000→/**
  1001→ * Create data table for PDF
  1002→ */
  1003→function createDataTable(columns: string[], data: Record<string, unknown>[]): Content {
  1004→  // Limit columns displayed based on page width
  1005→  const displayColumns = columns.slice(0, 10);
  1006→
  1007→  // Header row
  1008→  const headerRow: TableCell[] = displayColumns.map((col) => ({
  1009→    text: formatColumnHeader(col),
  1010→    style: 'tableHeader',
  1011→    alignment: 'center',
  1012→  }));
  1013→
  1014→  // Data rows
  1015→  const dataRows: TableCell[][] = data.map((row, index) =>
  1016→    displayColumns.map((col) => ({
  1017→      text: String(formatCellValue(row[col], col) ?? ''),
  1018→      style: index % 2 === 0 ? 'tableCell' : 'tableCellAlt',
  1019→      alignment: isNumericColumn(col) ? 'right' : 'left',
  1020→    }))
  1021→  );
  1022→
  1023→  // Calculate column widths (equal distribution)
  1024→  const colWidth = (842 - 80) / displayColumns.length; // A4 landscape width minus margins
  1025→  const widths = displayColumns.map(() => colWidth);
  1026→
  1027→  return {
  1028→    table: {
  1029→      headerRows: 1,
  1030→      widths,
  1031→      body: [headerRow, ...dataRows],
  1032→    },
  1033→    layout: {
  1034→      hLineWidth: () => 0.5,
  1035→      vLineWidth: () => 0.5,
  1036→      hLineColor: () => '#DDDDDD',
  1037→      vLineColor: () => '#DDDDDD',
  1038→      paddingLeft: () => 4,
  1039→      paddingRight: () => 4,
  1040→      paddingTop: () => 2,
  1041→      paddingBottom: () => 2,
  1042→    },
  1043→  };
  1044→}
