  1076→                [{ text: 'Total Overhead Cost:', style: 'summaryLabel' }, { text: formatCurrency(summary['totalOverheadCost']), style: 'summaryValue', alignment: 'right' }],
  1077→                [{ text: 'Grand Total:', style: 'summaryLabel', bold: true }, { text: formatCurrency(summary['grandTotal']), style: 'summaryValue', alignment: 'right', bold: true }],
