  1124→                  [{ text: 'Trains Requiring Replan:', style: 'summaryLabel' }, { text: String(summary['trainsRequiringReplan']), style: 'summaryValue', alignment: 'right' }],
  1125→                  [{ text: 'Average Mileage Drift:', style: 'summaryLabel' }, { text: `${summary['avgMileageDriftPct']?.toFixed(2)}%`, style: 'summaryValue', alignment: 'right' }],
  1126→                  [{ text: 'Maximum PM Drift:', style: 'summaryLabel' }, { text: `${summary['maxPmDriftDays']} days`, style: 'summaryValue', alignment: 'right' }],
  1127→                ],
  1128→              },
