  1152→
  1153→    content.push({
  1154→      stack: alertList,
  1155→      margin: [10, 0, 0, 10],
  1156→    } as Content);
  1157→  }
  1158→
  1159→  return {
  1160→    stack: content,
  1161→    margin: [0, 0, 0, 20],
  1162→  };
  1163→}
  1164→
  1165→/**
  1166→ * Create fleet summary content for PDF
  1167→ */
  1168→function createFleetSummaryContent(data: FleetStatusRow[]): Content {
  1169→  const totalTrains = data.reduce((sum, r) => sum + r.totalTrains, 0);
  1170→  const totalFit = data.reduce((sum, r) => sum + r.fitTrains, 0);
  1171→  const totalRestricted = data.reduce((sum, r) => sum + r.restrictedTrains, 0);
  1172→  const totalGrounded = data.reduce((sum, r) => sum + r.groundedTrains, 0);
  1173→
  1174→  return {
  1175→    columns: [
  1176→      {
  1177→        width: '50%',
  1178→        stack: [
  1179→          { text: 'Fleet Overview', style: 'sectionHeader', margin: [0, 0, 0, 10] },
  1180→          {
  1181→            table: {
  1182→              widths: ['*', 'auto'],
  1183→              body: [
  1184→                [{ text: 'Total Fleets:', style: 'summaryLabel' }, { text: String(data.length), style: 'summaryValue', alignment: 'right' }],
  1185→                [{ text: 'Total Trains:', style: 'summaryLabel' }, { text: String(totalTrains), style: 'summaryValue', alignment: 'right' }],
  1186→              ],
  1187→            },
  1188→            layout: 'noBorders',
  1189→          },
  1190→        ],
  1191→      },
  1192→      {
  1193→        width: '50%',
  1194→        stack: [
  1195→          { text: 'Fitness Status', style: 'sectionHeader', margin: [0, 0, 0, 10] },
  1196→          {
  1197→            table: {
  1198→              widths: ['*', 'auto'],
  1199→              body: [
  1200→                [{ text: 'FIT:', style: 'summaryLabel' }, { text: `${totalFit} (${((totalFit / totalTrains) * 100).toFixed(1)}%)`, style: 'summaryValue', alignment: 'right' }],
  1201→                [{ text: 'RESTRICTED:', style: 'summaryLabel' }, { text: `${totalRestricted} (${((totalRestricted / totalTrains) * 100).toFixed(1)}%)`, style: 'summaryValue', alignment: 'right' }],
  1202→                [{ text: 'GROUNDED:', style: 'summaryLabel' }, { text: `${totalGrounded} (${((totalGrounded / totalTrains) * 100).toFixed(1)}%)`, style: 'summaryValue', alignment: 'right' }],
  1203→              ],
  1204→            },
  1205→            layout: 'noBorders',
  1206→          },
  1207→        ],
  1208→      },
  1209→    ],
  1210→    margin: [0, 0, 0, 20],
  1211→  };
  1212→}
  1213→
  1214→// =============================================================================
  1215→// Utilities
  1216→// =============================================================================
  1217→
  1218→/**
  1219→ * Ensure output directory exists
  1220→ */
  1221→async function ensureOutputDir(): Promise<void> {
  1222→  try {
  1223→    await fs.access(REPORTS_OUTPUT_DIR);
  1224→  } catch {
  1225→    await fs.mkdir(REPORTS_OUTPUT_DIR, { recursive: true });
  1226→    log.info({ dir: REPORTS_OUTPUT_DIR }, 'Created reports output directory');
  1227→  }
  1228→}
  1229→
  1230→/**
  1231→ * Format file size for display
  1232→ */
  1233→function formatFileSize(bytes: number): string {
  1234→  if (bytes < 1024) return `${bytes} B`;
  1235→  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  1236→  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  1237→}
  1238→
  1239→/**
  1240→ * Format report type as human-readable title
  1241→ */
  1242→function formatReportTitle(type: string): string {
  1243→  const titles: Record<string, string> = {
  1244→    pm_schedule: 'PM Schedule Export',
  1245→    fleet_status: 'Fleet Status Report',
  1246→    drift_report: 'Drift Analysis Report',
  1247→    tco_projection: 'TCO Projection Report',
