// =============================================================================
// Worker Configuration
// =============================================================================

const log = logger.child({ worker: 'report' });

/** Output directory for generated reports */
const REPORTS_OUTPUT_DIR = process.env['REPORTS_OUTPUT_DIR'] ?? '/tmp/mms-reports';

/**
 * Base URL for report downloads
 * Note: In production or when using dynamic ports, set REPORTS_BASE_URL environment variable
 * to match the actual server address (e.g., http://localhost:<actual-port>/exports)
 */
const REPORTS_BASE_URL = process.env['REPORTS_BASE_URL'] ?? 'http://localhost:3000/exports';

/** Report retention period in hours */
const REPORT_RETENTION_HOURS = parseInt(process.env['REPORT_RETENTION_HOURS'] ?? '24', 10);

// =============================================================================
// Types
// =============================================================================

/** Report generation result */
export interface ReportResult {
  jobId: string;
  type: string;
  format: 'pdf' | 'excel';
  filePath: string;
  fileName: string;
  fileSizeBytes: number;
  downloadUrl: string;
  expiresAt: Date;
  generatedAt: Date;
  rowCount?: number;
  pageCount?: number;
}

// =============================================================================
// Job Processor
// =============================================================================

/**
 * Process report generation job
 *
 * Generates PDF or Excel reports based on the job configuration.
 * Saves output to file storage and returns download URL.
 */
export async function processReportJob(
  context: WorkerJobContext<ReportJobData>
): Promise<ReportResult> {
  return withSpan('worker.report.process', async (span) => {
    const { id, data } = context;
    const { type, format, filters, requestedBy } = data;

    span.setAttribute('jobId', id);
    span.setAttribute('reportType', type);
    span.setAttribute('format', format);
    span.setAttribute('requestedBy', requestedBy);

    log.info(
      {
        jobId: id,
        type,
        format,
        requestedBy,
        filters: Object.keys(filters ?? {}),
      },
      'Processing report generation job'
    );

    // Update progress: initializing
    await context.updateProgress({ stage: 'INITIALIZING', percent: 5 });
    await context.log(`Initializing ${type} report generation (${format})`);

    // Ensure output directory exists
    await ensureOutputDir();

    // Update progress: fetching data
    await context.updateProgress({ stage: 'FETCHING_DATA', percent: 20 });
    await context.log('Fetching report data');

    // Fetch data based on report type
    const reportData = await fetchReportData(type, filters);
    span.setAttribute('report.dataRows', reportData.rowCount);

    await context.log(`Loaded ${reportData.rowCount} records for report`);

    // Update progress: generating report
    await context.updateProgress({ stage: 'GENERATING', percent: 50 });
    await context.log(`Generating ${format.toUpperCase()} report`);

    // Generate report based on format
    let result: ReportResult;

    if (format === 'excel') {
      result = await generateExcelReport(id, type, reportData);
    } else {
      result = await generatePdfReport(id, type, reportData);
    }

    // Update progress: finalizing
    await context.updateProgress({ stage: 'FINALIZING', percent: 90 });

    log.info(
      {
        jobId: id,
        filePath: result.filePath,
        fileSizeBytes: result.fileSizeBytes,
        downloadUrl: result.downloadUrl,
        expiresAt: result.expiresAt,
      },
      'Report generation complete'
    );

    await context.log(
      `Report generated: ${result.fileName} (${formatFileSize(result.fileSizeBytes)})`
    );
    await context.log(`Download URL: ${result.downloadUrl}`);
    await context.log(`Expires: ${result.expiresAt.toISOString()}`);

    // Record metrics
    span.setAttribute('report.fileSizeBytes', result.fileSizeBytes);
    span.setAttribute('report.fileName', result.fileName);

    // Update progress: complete
    await context.updateProgress({ stage: 'COMPLETE', percent: 100 });

    return result;
  });
}

