/**
 * Generate Excel report using ExcelJS
 */
async function generateExcelReport(
  jobId: string,
  type: string,
  reportData: ReportData
): Promise<ReportResult> {
  return withSpan('report.generateExcel', async (span) => {
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
    const fileName = `${type}_${timestamp}.xlsx`;
    const filePath = path.join(REPORTS_OUTPUT_DIR, fileName);

    span.setAttribute('report.fileName', fileName);
    span.setAttribute('report.filePath', filePath);

    // Create workbook and worksheet
    const workbook = new ExcelJS.Workbook();
    workbook.creator = 'MMS Report Generator';
    workbook.created = new Date();

    const worksheet = workbook.addWorksheet(formatReportTitle(type));

    // Get columns from metadata
    const columns = (reportData.metadata['columns'] as string[]) ?? [];

    // Configure columns with headers and widths
    worksheet.columns = columns.map((col) => ({
      header: formatColumnHeader(col),
      key: col,
      width: getColumnWidth(col),
    }));

    // Style header row
    const headerRow = worksheet.getRow(1);
    headerRow.font = { bold: true, color: { argb: 'FFFFFFFF' } };
    headerRow.fill = {
      type: 'pattern',
      pattern: 'solid',
      fgColor: { argb: 'FF2E5A88' }, // MMS blue
    };
    headerRow.alignment = { vertical: 'middle', horizontal: 'center' };

    // Add data rows
    reportData.data.forEach((row) => {
      const rowData: Record<string, unknown> = {};
      columns.forEach((col) => {
        rowData[col] = formatCellValue(row[col], col);
      });
      worksheet.addRow(rowData);
    });

    // Apply alternating row colors
    worksheet.eachRow((row, rowNumber) => {
      if (rowNumber > 1 && rowNumber % 2 === 0) {
        row.fill = {
          type: 'pattern',
          pattern: 'solid',
          fgColor: { argb: 'FFF5F5F5' },
        };
      }
    });

    // Add filters to first row if supported
    if (reportData.rowCount > 0) {
      worksheet.autoFilter = {
        from: { row: 1, column: 1 },
        to: { row: 1, column: columns.length },
      };
    }

    // Add metadata sheet
    const metaSheet = workbook.addWorksheet('Report Info');
    metaSheet.addRow(['Report Type', formatReportTitle(type)]);
    metaSheet.addRow(['Generated At', reportData.metadata['generatedAt']]);
    metaSheet.addRow(['Total Records', reportData.rowCount]);

    // Add summary data for specific report types
    if (type === 'tco_projection' && reportData.metadata['summary']) {
      const summary = reportData.metadata['summary'] as Record<string, number>;
      metaSheet.addRow([]);
      metaSheet.addRow(['TCO Summary']);
      metaSheet.addRow(['Total Labor Cost', formatCurrency(summary['totalLaborCost'])]);
      metaSheet.addRow(['Total Material Cost', formatCurrency(summary['totalMaterialCost'])]);
      metaSheet.addRow(['Total Overhead Cost', formatCurrency(summary['totalOverheadCost'])]);
      metaSheet.addRow(['Grand Total', formatCurrency(summary['grandTotal'])]);
      metaSheet.addRow(['NPV', formatCurrency(summary['npv'])]);
      metaSheet.addRow(['Average Annual Cost', formatCurrency(summary['avgAnnualCost'])]);
    }

    if (type === 'drift_report' && reportData.metadata['summary']) {
      const summary = reportData.metadata['summary'] as Record<string, number>;
      metaSheet.addRow([]);
      metaSheet.addRow(['Drift Analysis Summary']);
      metaSheet.addRow(['Total Trains Analyzed', summary['totalTrainsAnalyzed']]);
      metaSheet.addRow(['Trains Requiring Replan', summary['trainsRequiringReplan']]);
      metaSheet.addRow(['Average Mileage Drift %', `${summary['avgMileageDriftPct']?.toFixed(2)}%`]);
      metaSheet.addRow(['Maximum PM Drift Days', summary['maxPmDriftDays']]);
    }

    metaSheet.columns = [
      { width: 25 },
      { width: 30 },
    ];

    // Write to file
    await workbook.xlsx.writeFile(filePath);

    const stats = await fs.stat(filePath);
    const expiresAt = new Date(Date.now() + REPORT_RETENTION_HOURS * 60 * 60 * 1000);

    return {
      jobId,
      type,
      format: 'excel',
      filePath,
      fileName,
      fileSizeBytes: stats.size,
      downloadUrl: `${REPORTS_BASE_URL}/${fileName}`,
      expiresAt,
      generatedAt: new Date(),
      rowCount: reportData.rowCount,
    };
  });
}

/**
 * Get appropriate column width based on column name
 */
function getColumnWidth(col: string): number {
  const widths: Record<string, number> = {
    trainNumber: 12,
    fleetCode: 10,
    fleetName: 20,
    pmCode: 8,
    targetDate: 12,
    status: 12,
    constraintStart: 14,
    constraintEnd: 14,
    assignedDepot: 15,
    assignedTrack: 12,
    estimatedHours: 14,
    maximoWoId: 15,
    isLocked: 8,
    totalTrains: 12,
    fitTrains: 10,
    restrictedTrains: 14,
    groundedTrains: 14,
    avgMileageKm: 14,
    minMileageKm: 12,
    maxMileageKm: 12,
    stdDevMileageKm: 14,
    baselineProjectedKm: 18,
    actualKm: 12,
    mileageDriftPct: 14,
    avgPmDriftDays: 14,
    maxPmDriftDays: 14,
    requiresReplan: 14,
    replanReason: 25,
    fiscalYear: 12,
    laborCost: 14,
    materialCost: 14,
    overheadCost: 14,
    totalCost: 14,
    pmCount: 10,
    inflationFactor: 14,
  };
  return widths[col] ?? 15;
}

/**
 * Format column header from camelCase to Title Case
 */
function formatColumnHeader(col: string): string {
  return col
    .replace(/([A-Z])/g, ' $1')
    .replace(/^./, (str) => str.toUpperCase())
    .replace(/Km/g, '(km)')
    .replace(/Pct/g, '(%)')
    .trim();
}

/**
 * Format cell value for display
 */
function formatCellValue(value: unknown, col: string): string | number | boolean | Date | null {
  if (value === null || value === undefined) return '';

  // Currency columns
  if (['laborCost', 'materialCost', 'overheadCost', 'totalCost'].includes(col)) {
    return typeof value === 'number' ? value : parseFloat(String(value)) || 0;
  }

  // Percentage columns
  if (col.includes('Pct')) {
    return typeof value === 'number' ? `${value.toFixed(2)}%` : String(value);
  }

  // Boolean columns
  if (typeof value === 'boolean') {
    return value ? 'Yes' : 'No';
  }

  // Date columns
  if (col.includes('Date') && typeof value === 'string') {
    return value;
  }

  return value as string | number | boolean | Date;
}

/**
 * Format currency value
 */
function formatCurrency(value: number | undefined): string {
  if (value === undefined) return 'N/A';
  return new Intl.NumberFormat('en-SG', {
    style: 'currency',
    currency: 'SGD',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(value);
}

